#!/usr/bin/env bash
set -euo pipefail; source "$(dirname "$0")/lib/android-test.sh"; abi=x86_64; serial=emulator-5554; while (($#)); do case "$1" in --android-abi) abi="${2:?}";shift 2;;--serial) serial="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done; archphene_validate_choice "$abi" ABI x86_64 arm64-v8a; archphene_test_init "$serial"; apk="$ARCHPHENE_ROOT/prototypes/native-compositor-probe/out-$abi/archphene-compositor-probe.apk"; receiver="$ARCHPHENE_ROOT/prototypes/uri-grant-receiver-probe/out-$abi/archphene-uri-grant-receiver-probe.apk"; archphene_require_file "$apk"; archphene_require_file "$receiver"; archphene_adb_run install -r "$apk" >/dev/null; archphene_adb_run install -r "$receiver" >/dev/null
probe(){ local flag="$1" pass="$2" fail="$3"; archphene_adb_run logcat -c; archphene_adb_run shell am force-stop org.archphene.compositorprobe; archphene_adb_run shell am start -n org.archphene.compositorprobe/.MainActivity --ez "$flag" true >/dev/null; log="$(archphene_wait_log "$pass|$fail" 30 'ArchpheneCompositorProbe:I *:S')"; [[ "$log" == *"$pass"* ]] || archphene_die "$fail"; }; probe drag_only 'Native drag-and-drop probe passed' 'Native drag-and-drop probe failed'; probe document_drag_only 'Document drag broker probe passed' 'Document drag broker probe failed'; for grant in false true; do archphene_adb_run logcat -c; archphene_adb_run shell am force-stop org.archphene.compositorprobe; archphene_adb_run shell am start -n org.archphene.compositorprobe/.MainActivity --ez provider_grant_only true --ez grant_provider_uri "$grant" >/dev/null; expected='URI read denied'; [[ "$grant" == true ]] && expected='URI read passed ARCHPHENE_OUTBOUND_URI_GRANT'; archphene_wait_log "$expected" 30 'ArchpheneUriGrantProbe:I ArchpheneCompositorProbe:I *:S' >/dev/null; done; archphene_note "Android/Wayland text and document drag-and-drop passed on $serial ($abi)."
